const raw = $input.first().json;
const params = raw.parameters ?? {};
const stixBundle = params.stix_bundle ?? null;
const objectType = params.object_type ?? null;
const objectId = params.object_id ?? null;
const proposedActionId = raw.proposed_action_id ?? 'unknown';
if (!stixBundle && !objectType) throw new Error('Sandbox: parameters.stix_bundle or parameters.object_type is required');
return [{ json: { stix_bundle: stixBundle, object_type: objectType, object_id: objectId, proposed_action_id: proposedActionId, action: raw.action, requester: raw.requester } }];

const bundle = $input.item.json;
const input = $('Normalise Input').first().json;
if (bundle.errors?.length) throw new Error('OpenCTI GraphQL error: ' + bundle.errors.map(e => e.message).join('; '));
const importId = bundle.data?.stixBundleImport?.id ?? null;
const success = !!importId;
return [{ json: {
  status: success ? 'success' : 'failed',
  result_summary: success ? `STIX bundle imported to OpenCTI. Import ID: ${importId}` : 'STIX bundle import returned no ID — check OpenCTI logs.',
  raw_result_ref: importId,
  proposed_action_id: input.proposed_action_id
} }];

const obj = $input.item.json;
const input = $('Normalise Input').first().json;
if (obj.errors?.length) throw new Error('OpenCTI GraphQL error: ' + obj.errors.map(e => e.message).join('; '));
const found = obj.data?.stixObjectOrStixRelationship ?? null;
const success = !!found;
return [{ json: {
  status: success ? 'success' : 'partial',
  result_summary: success ? `Object ${found.standard_id} (${found.entity_type}) found in OpenCTI.` : `Object ID ${input.object_id} not found in OpenCTI.`,
  raw_result_ref: found?.standard_id ?? null,
  proposed_action_id: input.proposed_action_id
} }];
